+#[test]
+fn inet_ntop_ipv4_buffer_too_small_returns_null() {
+    let addr: [u8; 4] = [192, 168, 1, 1];
+    let mut buf = [0u8; 4]; // Too small for "192.168.1.1\0"
+    let ret = unsafe {
+        inet_ntop(
+            AF_INET,
+            addr.as_ptr().cast(),
+            buf.as_mut_ptr().cast(),
+            buf.len() as u32,
