+}
+
+#[test]
+fn inet_ntop_ipv6_loopback() {
+    let mut addr = [0u8; 16];
+    addr[15] = 1;
+    let mut buf = [0u8; 46]; // INET6_ADDRSTRLEN
+    let ret = unsafe {
+        inet_ntop(
+            AF_INET6,
+            addr.as_ptr().cast(),
+            buf.as_mut_ptr().cast(),
