+
+#[test]
+fn inet_ntop_ipv6_all_zeros() {
+    let addr = [0u8; 16];
+    let mut buf = [0u8; 46];
+    let ret = unsafe {
+        inet_ntop(
+            AF_INET6,
+            addr.as_ptr().cast(),
+            buf.as_mut_ptr().cast(),
