+}
+
+#[test]
+fn inet_addr_invalid_returns_none() {
+    let src = CString::new("not_an_address").unwrap();
+    let result = unsafe { inet_addr(src.as_ptr()) };
+    assert_eq!(result, INADDR_NONE);
+}
+
+#[test]
+fn inet_addr_empty_returns_none() {
+    let src = CString::new("").unwrap();
+    let result = unsafe { inet_addr(src.as_ptr()) };
