+    unsafe { time_abi::gmtime_r(&now, &mut tm) };
+
+    let reconstructed = unsafe { time_abi::timegm(&mut tm) };
+    assert_eq!(now, reconstructed, "timegm(gmtime(t)) should roundtrip exactly");
+}
