+    // TIME_UTC = 1 in C11
+    let rc = unsafe { time_abi::timespec_get(&mut ts, 1) };
+    assert_eq!(rc, 1, "timespec_get with TIME_UTC should return TIME_UTC");
+    assert!(ts.tv_sec > 0);
+    assert!(ts.tv_nsec >= 0 && ts.tv_nsec < 1_000_000_000);
+}
