+    let mut ts: libc::timespec = unsafe { std::mem::zeroed() };
+    let rc = unsafe { time_abi::timespec_getres(&mut ts, 1) };
+    assert_eq!(rc, 1, "timespec_getres with TIME_UTC should return TIME_UTC");
+    assert!(ts.tv_nsec >= 0);
+}
